  questionSet?: Prisma.QuestionSetOmit
  generatedQuestion?: Prisma.GeneratedQuestionOmit
  retrievalLog?: Prisma.RetrievalLogOmit
  concept?: Prisma.ConceptOmit
  conceptEdge?: Prisma.ConceptEdgeOmit
  studyPack?: Prisma.StudyPackOmit
  flashcard?: Prisma.FlashcardOmit
  practiceQuestion?: Prisma.PracticeQuestionOmit
